{"YHZP_SEGMENT_ID":"YHZP-USR-S00052","SOURCE_ROOT_ATOM_ID":"YHZP-ROOT-005-0004","SOURCE_FAMILY_ID":"YHZP-USER-CLEANED-ROOT-03","CHAPTER_NO":5,"CHAPTER_TITLE":"十干所属方位十二支所属论","SOURCE_PHYSICAL_LINE_NO":236,"SOURCE_LINE_SEQ_IN_CHAPTER":4,"SOURCE_LAYER":"CLASSICAL_ORIGINAL","RAW_TEXT":"是时大挠氏虽以甲乙属木，丙丁属火，戊己属土，庚辛属金，壬癸属水。又以支元寅卯属木，巳午属火，申酉属金，亥子属水，辰戌丑未属土，其理何义？或曰：东方有神太昊，乘震执规司春，生仁风和气，万物发生，所以木居之故，甲乙寅卯同也。","RAW_TEXT_SHA256":"8cc20eb235323fed2220561fddac7b8bb5ded8b80bb2b4d59fc0bc3cde09bfee","LOGICAL_OPERATOR_HINTS":["ALTERNATIVE_OR_PARALLEL","CAUSAL","CONDITION","LIMITATION_OR_CONTRAST","NEGATION","QUANTITY","REFERENCE","SEQUENCE"],"PRIMARY_AUTHORITY_LIBRARY":"S11","CROSS_ROUTES":[],"CURRENT_ASTROLOGICAL_CONTRIBUTION":"FUTURE_CONDITIONAL_ONLY","CURRENT_CASE_EVIDENCE_PERMISSION":"NO","DIRECT_EVENT_PERMISSION":"NO","DIRECT_ENDPOINT_PERMISSION":"NO","DIRECT_SCORE_PERMISSION":"NO","STATUS":"ACTIVE_SOURCE","PARENT_CHAPTER_ID":"YHZP-CH-005","PREV_SEGMENT_ID":"YHZP-USR-S00051","NEXT_SEGMENT_ID":"YHZP-USR-S00053"}

