{"YHZP_SEGMENT_ID":"YHZP-USR-S00053","SOURCE_ROOT_ATOM_ID":"YHZP-ROOT-005-0005","SOURCE_FAMILY_ID":"YHZP-USER-CLEANED-ROOT-03","CHAPTER_NO":5,"CHAPTER_TITLE":"十干所属方位十二支所属论","SOURCE_PHYSICAL_LINE_NO":238,"SOURCE_LINE_SEQ_IN_CHAPTER":5,"SOURCE_LAYER":"CLASSICAL_ORIGINAL","RAW_TEXT":"南方有神农帝，乘离执衡司夏，生艳阳酷气，万物至此咸齐，所以火居之故，丙丁巳午同也。(夏天主长育万物，草木茂盛，咸赖火德之功也。)","RAW_TEXT_SHA256":"1d4b9818ff7a2ac6a2010820a684c347a621b184cda62cdc609d3fe02c718973","LOGICAL_OPERATOR_HINTS":["CAUSAL","CONDITION","QUANTITY","REFERENCE","SEQUENCE"],"PRIMARY_AUTHORITY_LIBRARY":"S11","CROSS_ROUTES":[],"CURRENT_ASTROLOGICAL_CONTRIBUTION":"FUTURE_CONDITIONAL_ONLY","CURRENT_CASE_EVIDENCE_PERMISSION":"NO","DIRECT_EVENT_PERMISSION":"NO","DIRECT_ENDPOINT_PERMISSION":"NO","DIRECT_SCORE_PERMISSION":"NO","STATUS":"ACTIVE_SOURCE","PARENT_CHAPTER_ID":"YHZP-CH-005","PREV_SEGMENT_ID":"YHZP-USR-S00052","NEXT_SEGMENT_ID":"YHZP-USR-S00054"}

