{"YHZP_SEGMENT_ID":"YHZP-USR-S00427","SOURCE_ROOT_ATOM_ID":"YHZP-ROOT-061-0003","SOURCE_FAMILY_ID":"YHZP-USER-CLEANED-ROOT-03","CHAPTER_NO":61,"CHAPTER_TITLE":"地支藏遁歌","SOURCE_PHYSICAL_LINE_NO":2624,"SOURCE_LINE_SEQ_IN_CHAPTER":3,"SOURCE_LAYER":"CLASSICAL_ORIGINAL","RAW_TEXT":"子宫癸水在其中，丑癸辛金己土同，寅宫甲木兼丙戊，卯宫乙木独相逢，辰藏乙戊三分癸，巳中庚金丙戊丛，午宫丁火拼己土，未宫乙己丁其宗，申位庚金壬水戊，酉宫辛字独丰隆，戌宫辛金及丁戊，亥中壬甲是真踪。","RAW_TEXT_SHA256":"c6dee5f951f330a0ba0a9b161ed728cdfe7e9a7f65227c17cebab70805394366","LOGICAL_OPERATOR_HINTS":["ALTERNATIVE_OR_PARALLEL","CONDITION","NEGATION","QUANTITY","REFERENCE","SEQUENCE"],"PRIMARY_AUTHORITY_LIBRARY":"S15","CROSS_ROUTES":["S13"],"CURRENT_ASTROLOGICAL_CONTRIBUTION":"FUTURE_CONDITIONAL_ONLY","CURRENT_CASE_EVIDENCE_PERMISSION":"NO","DIRECT_EVENT_PERMISSION":"NO","DIRECT_ENDPOINT_PERMISSION":"NO","DIRECT_SCORE_PERMISSION":"NO","STATUS":"ACTIVE_SOURCE","PARENT_CHAPTER_ID":"YHZP-CH-061","PREV_SEGMENT_ID":"YHZP-USR-S00426","NEXT_SEGMENT_ID":null}
